172	static bstring* newshortstr(bvm *vm, const char *str, size_t len)
173	{
174	    bstring *s;
175	    int size = vm->strtab.size;
176	    uint32_t hash = str_hash(str, len);
177	    bstring **list = vm->strtab.table + (hash & (size - 1));
178	
179	    for (s = *list; s != NULL; s = next(s)) {
180	        if (len == s->slen && !strncmp(str, sstr(s), len)) {
181	            return s;
182	        }
183	    }
184	    s = createstrobj(vm, len, 0);
185	    if (s) {
186	        memcpy(cast(char *, sstr(s)), str, len);
187	        s->extra = 0;
188	        s->next = cast(void*, *list);
189	#if BE_USE_STR_HASH_CACHE
190	        cast(bsstring*, s)->hash = hash;
191	#endif
192	        *list = s;
193	        vm->strtab.count++;
194	        if (vm->strtab.count > size << 2) {
195	            resize(vm, size << 1);
196	        }
197	    }
198	    return s;
199	}
