233	void be_gcstrtab(bvm *vm)
234	{
235	    struct bstringtable *tab = &vm->strtab;
236	    int size = tab->size, i;
237	    for (i = 0; i < size; ++i) {
238	        bstring **list = tab->table + i;
239	        bstring *prev = NULL, *node, *next;
240	        for (node = *list; node; node = next) {
241	            next = next(node);
242	            if (!gc_isfixed(node) && gc_iswhite(node)) {
243	                free_sstring(vm, node);
244	                tab->count--;
245	                if (prev) { /* link list */
246	                    prev->next = cast(void*, next);
247	                } else {
248	                    *list = next;
249	                }
250	            } else {
251	                prev = node;
252	                gc_setwhite(node);
253	            }
254	        }
255	    }
256	    if (tab->count < size >> 2 && size > 8) {
257	        resize(vm, size >> 1);
258	    }
259	}
