261	uint32_t be_strhash(const bstring *s)
262	{
263	    if (gc_isconst(s)) {
264	        bcstring* cs = cast(bcstring*, s);
265	        if (cs->hash) {  /* if hash is null we need to compute it */
266	            return cs->hash;
267	        } else {
268	            return str_hash(cstr(s), str_len(s));
269	        }
270	    }
271	#if BE_USE_STR_HASH_CACHE
272	    if (s->slen != 255) {
273	        return cast(bsstring*, s)->hash;
274	    }
275	#endif
276	    return str_hash(str(s), str_len(s));
277	}
