231	/*******************************************************************
232	 * the function be_str2int():
233	 * >>-+------------+--+-----+----digits----><
234	 *    '-whitespace-'  +- + -+
235	 *                    '- - -'
236	 *******************************************************************/
237	BERRY_API bint be_str2int(const char *str, const char **endstr)
238	{
239	    int c, sign;
240	    bint sum = 0;
241	    skip_space(str);
242	    sign = c = *str++;
243	    if (c == '+' || c == '-') {
244	        c = *str++;
245	    }
246	    while (is_digit(c)) {
247	        sum = sum * 10 + c - '0';
248	        c = *str++;
249	    }
250	    if (endstr) {
251	        *endstr = str - 1;
252	    }
253	    return sign == '-' ? -sum : sum;
254	}
255	
256	/*******************************************************************
257	 * the function be_str2real():
258	 * >>-+------------+--+-----+--+-digits--+---+--+--------+-+------->
259	 *    '-whitespace-'  +- + -+  |         '-.-'  '-digits-' |   
260	 *                    '- - -'  '-.--digits-----------------'   
261	 * 
262	 * >--+------------------------+----------------------------------><
263	 *    '-+-e-+--+-----+--digits-'   
264	 *      '-E-'  +- + -+             
265	 *             '- - -'  
266	 *******************************************************************/
267	BERRY_API breal be_str2real(const char *str, const char **endstr)
268	{
269	    int c, sign;
270	    breal sum = 0, deci = 0, point = (breal)0.1;
271	    skip_space(str);
272	    sign = c = *str++;
273	    if (c == '+' || c == '-') {
274	        c = *str++;
275	    }
276	    while (is_digit(c)) {
277	        sum = sum * 10 + c - '0';
278	        c = *str++;
279	    }
280	    if (c == '.') {
281	        c = *str++;
282	        while (is_digit(c)) {
283	            deci = deci + ((breal)c - '0') * point;
284	            point *= (breal)0.1;
285	            c = *str++;
286	        }
287	    }
288	    sum = sum + deci;
289	    if (c == 'e' || c == 'E') {
290	        int e = 0;
291	        breal ratio = (c = *str++) == '-' ? (breal)0.1 : 10;
292	        if (c == '+' || c == '-') {
293	            c = *str++;
294	        }
295	        while (is_digit(c)) {
296	            e = e * 10 + c - '0';
297	            c = *str++;
298	        }
299	        while (e--) {
300	            sum *= ratio;
301	        }
302	    }
303	    if (endstr) {
304	        *endstr = str - 1;
305	    }
306	    return sign == '-' ? -sum : sum;
307	}
